import collections

class PushRelabel:
    def __init__(self, n_nodes, source, sink):
        self.n = n_nodes
        self.s = source
        self.t = sink
        self.adj = [[] for _ in range(n_nodes)]
        self.height = [0] * n_nodes
        self.excess = [0] * n_nodes
        self.current = [0] * n_nodes
        self.active_list = collections.deque()

    def add_edge(self, u, v, capacity):
        u_to_v_edge_idx = len(self.adj[u])
        v_to_u_edge_idx = len(self.adj[v])
        self.adj[u].append(self._Edge(v, capacity, v_to_u_edge_idx))
        self.adj[v].append(self._Edge(u, 0, u_to_v_edge_idx))

    class _Edge:
        def __init__(self, to, capacity, rev_idx):
            self.to = to
            self.capacity = capacity
            self.flow = 0
            self.rev_idx = rev_idx

    def _push(self, u, edge_idx):
        edge_uv = self.adj[u][edge_idx]
        v = edge_uv.to

        residual_cap = edge_uv.capacity - edge_uv.flow

        flow_delta = min(self.excess[u], residual_cap)

        if flow_delta == 0:
            return

        edge_uv.flow += flow_delta
        self.adj[v][edge_uv.rev_idx].flow -= flow_delta

        self.excess[u] -= flow_delta

        if v != self.s and v != self.t and self.excess[v] == 0:
            self.active_list.append(v)
        self.excess[v] += flow_delta

    def _relabel(self, u):
        min_height = float('inf')
        for edge_uv in self.adj[u]:
            if edge_uv.capacity - edge_uv.flow > 0:
                min_height = min(min_height, self.height[edge_uv.to])

        if min_height == float('inf'):
            self.height[u] = self.n + 1
        else:
            self.height[u] = min_height + 1

        self.current[u] = 0

    def _discharge(self, u):
        while self.excess[u] > 0:
            if self.current[u] == len(self.adj[u]):
                self._relabel(u)
            else:
                edge_uv = self.adj[u][self.current[u]]
                v = edge_uv.to
                residual_cap = edge_uv.capacity - edge_uv.flow

                if residual_cap > 0 and self.height[u] == self.height[v] + 1:
                    self._push(u, self.current[u])
                else:
                    self.current[u] += 1

    def max_flow(self):
        self.height[self.s] = self.n

        for edge_idx, edge_sv in enumerate(self.adj[self.s]):
            v = edge_sv.to
            flow_delta = edge_sv.capacity

            if flow_delta == 0: continue

            edge_sv.flow += flow_delta
            self.adj[v][edge_sv.rev_idx].flow -= flow_delta

            self.excess[self.s] -= flow_delta

            if v != self.s and v != self.t and self.excess[v] == 0:
                self.active_list.append(v)
            self.excess[v] += flow_delta

        while self.active_list:
            u = self.active_list.popleft()

            if u == self.s or u == self.t or self.excess[u] == 0:
                continue

            self._discharge(u)

            if self.excess[u] > 0:
                self.active_list.append(u)

        return self.excess[self.t]
